draw((0,0)..(-.5,-.5)..(-1,0));
draw((0,-1)..(-1/3,-2/3)..(0,-1/3));
draw((-1/2,0)--(0,-2/3));
label("$Q$",(0,0),NE);
label("$A$",(-1,0),W);
label("$B$",(0,-1),S);
label("$C$",(-1/2,0),N);
label("$D$",(0,-2/3),E);
dot((-1/2,0));
dot((0,-2/3));
label("$7$",(-7/20,-1/5),E);
label("$r$",(-1/10,-8/15),SW);[/asy]

